   106→/*****************************************************************************
   107→ * L2CACHE - AE350
   108→ ****************************************************************************/
   109→typedef struct {
   110→	__I  unsigned long long CFG;            /* 0x00 Configuration Register */
   111→	__IO unsigned long long CTL;            /* 0x08 Control Register */
   112→	__IO unsigned long long HPMCTL0;        /* 0x10 HPM Control Register0 */
   113→	__IO unsigned long long HPMCTL1;        /* 0x18 HPM Control Register1 */
   114→	__IO unsigned long long HPMCTL2;        /* 0x20 HPM Control Register2 */
   115→	__IO unsigned long long HPMCTL3;        /* 0x28 HPM Control Register3 */
   116→	__IO unsigned long long ASYNERR;        /* 0x30 Asynchronous Error Register */
   117→	__IO unsigned long long ERR;            /* 0x38 Error Register */
   118→	union {
   119→		struct {
   120→			__IO unsigned long long CORE0CCTLCMD;   /* 0x40 Core 0 CCTL Command Register */
   121→			__IO unsigned long long CORE0CCTLACC;   /* 0x48 Core 0 CCTL Access Line Register */
   122→			__IO unsigned long long CORE1CCTLCMD;   /* 0x50 Core 1 CCTL Command Register */
   123→			__IO unsigned long long CORE1CCTLACC;   /* 0x58 Core 1 CCTL Access Line Register */
   124→			__IO unsigned long long CORE2CCTLCMD;   /* 0x60 Core 2 CCTL Command Register */
   125→			__IO unsigned long long CORE2CCTLACC;   /* 0x68 Core 2 CCTL Access Line Register */
   126→			__IO unsigned long long CORE3CCTLCMD;   /* 0x70 Core 3 CCTL Command Register */
   127→			__IO unsigned long long CORE3CCTLACC;   /* 0x78 Core 3 CCTL Access Line Register */
   128→			__I  unsigned long long CCTLSTATUS;     /* 0x80 CCTL Status Register */
   129→			     unsigned long long RESERVED0;      /* 0x88 Reserved */
   130→			__IO unsigned long long TGTWDATA[4];    /* 0x90 ~ 0xAF TGT Write Data 0 to 3 */
   131→			__I  unsigned long long TGTRDATA[4];    /* 0xB0 ~ 0xCF TGT Read Data 0 to 3 */
   132→			__IO unsigned long long TGTWECC;        /* 0xD0 TGT Write ECC Code Register */
   133→			__I  unsigned long long TGTRECC;        /* 0xD8 TGT Read ECC Code Register */
   134→			     unsigned long long RESERVED1[36];  /* 0xE0 ~ 0x1FF Reserved */
   135→			__IO unsigned long long HPMCNT[32];     /* 0x200 ~ 0x2F8 HPM Counter Register 0 to 31 */
   136→			__I  unsigned long long WAYMASK[16];    /* 0x300 ~ 0x378 Way Allocation Mask Register 0 to 15 */
   137→		} REG;
   138→		struct {
   139→			__IO unsigned long long CCTLCMD;        /* 0x40 Core 0 CCTL Command Register */
   140→			__IO unsigned long long CCTLACC;        /* 0x48 Core 0 CCTL Access Line Register */
   141→			     unsigned long long RESERVED0[6];   /* 0x50 ~ 0x7F Reserved */
   142→			__I  unsigned long long CCTLSTATUS;     /* 0x80 Core 0 CCTL Status Register */
   143→			     unsigned long long RESERVED[503];  /* 0x88 Reserved */
   144→		} CORECCTL[8];
   145→	};
   146→} L2C_RegDef;
